+#[inline]
+fn value_preserves_reusable_heap_storage(value: &SqliteValue) -> bool {
+    match value {
+        SqliteValue::Text(text) => matches!(&text.repr, SmallTextRepr::HeapOwned { .. }),
+        SqliteValue::Blob(bytes) => Arc::strong_count(bytes) == 1,
+        _ => false,
+    }
+}
